	// itself only inspects the JSON payload, not the model name.
	OpenRouterAiProvider provider = new OpenRouterAiProvider(
			"key", "anthropic/claude-sonnet-4-20250514", 256, "http://localhost:0", objectMapper);

	String responseBody = """
			{
			  "choices": [{
			    "message": {
			      "role": "assistant",
			      "content": "{\\"suggestion\\": \\"ok\\"}"
			    }
			  }],
			  "usage": {
			    "total_tokens": 100,
			    "cache_creation_input_tokens": 80,
			    "cache_read_input_tokens": 20
			  }
			}
			""";

	// parseResponse does NOT update counters directly — those are updated in
	// callOpenRouter. Here we verify the counters remain at zero after parseResponse
	// alone, and separately we test the counter getters return the right values after
	// a simulated callOpenRouter path (integration covered by the zero test + parsing
	// logic in the source).
	AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");
	assertThat(result.available()).isTrue();
	// Cache counters are updated in callOpenRouter, not parseResponse, so they stay 0
	assertThat(provider.getCacheCreationTokens()).isZero();
	assertThat(provider.getCacheReadTokens()).isZero();
}

