package com.weeklycommit.domain.entity;

import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.Table;
import java.time.Instant;
import java.time.LocalDate;
import java.util.UUID;

/**
 * Derived read-model: per-user per-week aggregate fact table. Refreshed by
 * {@code ReadModelRefreshService} on lifecycle events and on a 5-minute
 * scheduled cadence.
 */
@Entity
@Table(name = "user_week_fact")
public class UserWeekFact {

	@Id
	@GeneratedValue(strategy = GenerationType.UUID)
	@Column(nullable = false, updatable = false)
	private UUID id;

	@Column(name = "user_id", nullable = false)
	private UUID userId;

	@Column(name = "week_start", nullable = false)
	private LocalDate weekStart;

	@Column(name = "plan_state")
	private String planState;

	@Column(name = "lock_compliance", nullable = false)
	private boolean lockCompliance;

	@Column(name = "reconcile_compliance", nullable = false)
	private boolean reconcileCompliance;

	@Column(name = "total_planned_points", nullable = false)
	private int totalPlannedPoints;

	@Column(name = "total_achieved_points", nullable = false)
	private int totalAchievedPoints;

	@Column(name = "commit_count", nullable = false)
	private int commitCount;

	@Column(name = "carry_forward_count", nullable = false)
	private int carryForwardCount;

	@Column(name = "scope_change_count", nullable = false)
	private int scopeChangeCount;

	@Column(name = "king_count", nullable = false)
	private int kingCount;

	@Column(name = "queen_count", nullable = false)
	private int queenCount;

	@Column(name = "refreshed_at", nullable = false)
	private Instant refreshedAt = Instant.now();

	// ---- Getters / Setters -----------------------------------------------

	public UUID getId() {
		return id;
	}
	public void setId(UUID id) {
		this.id = id;
	}

	public UUID getUserId() {
		return userId;
	}
	public void setUserId(UUID userId) {
		this.userId = userId;
	}

	public LocalDate getWeekStart() {
		return weekStart;
	}
	public void setWeekStart(LocalDate weekStart) {
		this.weekStart = weekStart;
	}

	public String getPlanState() {
		return planState;
	}
	public void setPlanState(String planState) {
		this.planState = planState;
	}

	public boolean isLockCompliance() {
		return lockCompliance;
	}
	public void setLockCompliance(boolean lockCompliance) {
		this.lockCompliance = lockCompliance;
	}

	public boolean isReconcileCompliance() {
		return reconcileCompliance;
	}
	public void setReconcileCompliance(boolean reconcileCompliance) {
		this.reconcileCompliance = reconcileCompliance;
	}

	public int getTotalPlannedPoints() {
		return totalPlannedPoints;
	}
	public void setTotalPlannedPoints(int totalPlannedPoints) {
		this.totalPlannedPoints = totalPlannedPoints;
	}

	public int getTotalAchievedPoints() {
		return totalAchievedPoints;
	}
	public void setTotalAchievedPoints(int totalAchievedPoints) {
		this.totalAchievedPoints = totalAchievedPoints;
	}

	public int getCommitCount() {
		return commitCount;
	}
	public void setCommitCount(int commitCount) {
		this.commitCount = commitCount;
	}

	public int getCarryForwardCount() {
		return carryForwardCount;
	}
	public void setCarryForwardCount(int carryForwardCount) {
		this.carryForwardCount = carryForwardCount;
	}

	public int getScopeChangeCount() {
		return scopeChangeCount;
	}
	public void setScopeChangeCount(int scopeChangeCount) {
		this.scopeChangeCount = scopeChangeCount;
	}

	public int getKingCount() {
		return kingCount;
	}
	public void setKingCount(int kingCount) {
		this.kingCount = kingCount;
	}

	public int getQueenCount() {
		return queenCount;
	}
	public void setQueenCount(int queenCount) {
		this.queenCount = queenCount;
	}

	public Instant getRefreshedAt() {
		return refreshedAt;
	}
	public void setRefreshedAt(Instant refreshedAt) {
		this.refreshedAt = refreshedAt;
	}
}

package com.weeklycommit.domain.entity;

import org.hibernate.annotations.ColumnTransformer;
import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.Table;
import java.time.Instant;
import java.time.LocalDate;
import java.util.UUID;

/**
 * Derived read-model: per-team per-week rollup. Refreshed on lifecycle events
 * and on a 5-minute scheduled cadence.
 *
 * <p>
 * {@code chessDistribution} stores a JSON object mapping chess-piece name to
 * count, e.g. {@code {"KING":1,"QUEEN":2,"ROOK":3}}.
 */
@Entity
@Table(name = "team_week_rollup")
public class TeamWeekRollup {

	@Id
	@GeneratedValue(strategy = GenerationType.UUID)
	@Column(nullable = false, updatable = false)
	private UUID id;

	@Column(name = "team_id", nullable = false)
	private UUID teamId;

	@Column(name = "week_start", nullable = false)
	private LocalDate weekStart;

	@Column(name = "member_count", nullable = false)
	private int memberCount;

	@Column(name = "locked_count", nullable = false)
	private int lockedCount;

	@Column(name = "reconciled_count", nullable = false)
	private int reconciledCount;

	@Column(name = "total_planned_points", nullable = false)
	private int totalPlannedPoints;

	@Column(name = "total_achieved_points", nullable = false)
	private int totalAchievedPoints;

	@Column(name = "exception_count", nullable = false)
	private int exceptionCount;

	@Column(name = "avg_carry_forward_rate", nullable = false)
	private double avgCarryForwardRate;

	/** JSON string — map of chess-piece name → count. */
	@ColumnTransformer(write = "?::jsonb")
	@Column(name = "chess_distribution", columnDefinition = "jsonb")
	private String chessDistribution;

	@Column(name = "refreshed_at", nullable = false)
	private Instant refreshedAt = Instant.now();

	// ---- Getters / Setters -----------------------------------------------

	public UUID getId() {
		return id;
	}
	public void setId(UUID id) {
		this.id = id;
	}

	public UUID getTeamId() {
		return teamId;
	}
	public void setTeamId(UUID teamId) {
		this.teamId = teamId;
	}

	public LocalDate getWeekStart() {
		return weekStart;
	}
	public void setWeekStart(LocalDate weekStart) {
		this.weekStart = weekStart;
	}

	public int getMemberCount() {
		return memberCount;
	}
	public void setMemberCount(int memberCount) {
		this.memberCount = memberCount;
	}

	public int getLockedCount() {
		return lockedCount;
	}
	public void setLockedCount(int lockedCount) {
		this.lockedCount = lockedCount;
	}

	public int getReconciledCount() {
		return reconciledCount;
	}
	public void setReconciledCount(int reconciledCount) {
		this.reconciledCount = reconciledCount;
	}

	public int getTotalPlannedPoints() {
		return totalPlannedPoints;
	}
	public void setTotalPlannedPoints(int totalPlannedPoints) {
		this.totalPlannedPoints = totalPlannedPoints;
	}

	public int getTotalAchievedPoints() {
		return totalAchievedPoints;
	}
	public void setTotalAchievedPoints(int totalAchievedPoints) {
		this.totalAchievedPoints = totalAchievedPoints;
	}

	public int getExceptionCount() {
		return exceptionCount;
	}
	public void setExceptionCount(int exceptionCount) {
		this.exceptionCount = exceptionCount;
	}

	public double getAvgCarryForwardRate() {
		return avgCarryForwardRate;
	}
	public void setAvgCarryForwardRate(double avgCarryForwardRate) {
		this.avgCarryForwardRate = avgCarryForwardRate;
	}

	public String getChessDistribution() {
		return chessDistribution;
	}
	public void setChessDistribution(String chessDistribution) {
		this.chessDistribution = chessDistribution;
	}

	public Instant getRefreshedAt() {
		return refreshedAt;
	}
	public void setRefreshedAt(Instant refreshedAt) {
		this.refreshedAt = refreshedAt;
	}
}

package com.weeklycommit.domain.entity;

import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.Table;
import java.time.Instant;
import java.time.LocalDate;
import java.util.UUID;

/**
 * Derived read-model: one row per active carry-forward commit, tracking
 * provenance and streak length.
 */
@Entity
@Table(name = "carry_forward_fact")
public class CarryForwardFact {

	@Id
	@GeneratedValue(strategy = GenerationType.UUID)
	@Column(nullable = false, updatable = false)
	private UUID id;

	/** The current (target) commit in the chain. */
	@Column(name = "commit_id", nullable = false)
	private UUID commitId;

	/** The week in which the original (root) commit was created. */
	@Column(name = "source_week", nullable = false)
	private LocalDate sourceWeek;

	/** The week in which this commit currently lives. */
	@Column(name = "current_week", nullable = false)
	private LocalDate currentWeek;

	/** Number of consecutive weeks this work has been carried forward. */
	@Column(name = "streak_length", nullable = false)
	private int streakLength;

	@Column(name = "rcdo_node_id")
	private UUID rcdoNodeId;

	@Column(name = "chess_piece")
	private String chessPiece;

	@Column(name = "refreshed_at", nullable = false)
	private Instant refreshedAt = Instant.now();

	// ---- Getters / Setters -----------------------------------------------

	public UUID getId() {
		return id;
	}
	public void setId(UUID id) {
		this.id = id;
	}

	public UUID getCommitId() {
		return commitId;
	}
	public void setCommitId(UUID commitId) {
		this.commitId = commitId;
	}

	public LocalDate getSourceWeek() {
		return sourceWeek;
	}
	public void setSourceWeek(LocalDate sourceWeek) {
		this.sourceWeek = sourceWeek;
	}

	public LocalDate getCurrentWeek() {
		return currentWeek;
	}
	public void setCurrentWeek(LocalDate currentWeek) {
		this.currentWeek = currentWeek;
	}

	public int getStreakLength() {
		return streakLength;
	}
	public void setStreakLength(int streakLength) {
		this.streakLength = streakLength;
	}

	public UUID getRcdoNodeId() {
		return rcdoNodeId;
	}
	public void setRcdoNodeId(UUID rcdoNodeId) {
		this.rcdoNodeId = rcdoNodeId;
	}

	public String getChessPiece() {
		return chessPiece;
	}
	public void setChessPiece(String chessPiece) {
		this.chessPiece = chessPiece;
	}

	public Instant getRefreshedAt() {
		return refreshedAt;
	}
	public void setRefreshedAt(Instant refreshedAt) {
		this.refreshedAt = refreshedAt;
	}
}

