package com.weeklycommit.ai.rag;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import java.util.Map;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

/**
 * Hypothetical Document Embedding (HyDE) service.
 *
 * <p>
 * Given a user's question, generates a short hypothetical answer that can be
 * embedded and used to augment semantic search retrieval. By embedding a
 * plausible answer alongside the question, the resulting vector is closer to
 * the actual document embeddings in the index.
 *
 * <p>
 * Gracefully degrades: returns {@code available=false} if the AI provider is
 * unavailable or the response cannot be parsed.
 *
 * <p>
 * This service is intended to be used as an opt-in enhancement to the RAG
 * pipeline, controlled by the {@code hyde} experiment flag (default off).
 */
@Service
public class HydeService {

    private static final Logger log = LoggerFactory.getLogger(HydeService.class);

    private final AiProviderRegistry aiProviderRegistry;
    private final ObjectMapper objectMapper;

    public HydeService(AiProviderRegistry aiProviderRegistry, ObjectMapper objectMapper) {
        this.aiProviderRegistry = aiProviderRegistry;
        this.objectMapper = objectMapper;
    }

    // ── Public API ───────────────────────────────────────────────────────

    /**
     * Generates a short hypothetical answer for the given {@code question}.
     *
     * <p>
     * The hypothetical answer is intended for embedding — it should NOT be shown
     * to the user directly.
     *
     * @param question the user's natural-language question
     * @param userId   the requesting user (for audit / experiment assignment)
     * @return a {@link HydeResult} with the generated answer, or
     *         {@code available=false} on any failure
     */
    public HydeResult generateHypothetical(String question, UUID userId) {
        if (question == null || question.isBlank()) {
            return HydeResult.unavailable();
        }

        Map<String, Object> additionalContext = Map.of("question", question);
        AiContext context =
                new AiContext(
                        AiContext.TYPE_HYDE,
                        userId,
                        null,
                        null,
                        Map.of(),
                        Map.of(),
                        java.util.List.of(),
                        java.util.List.of(),
                        additionalContext);

        try {
            AiSuggestionResult result = aiProviderRegistry.generateSuggestion(context);
            if (!result.available()) {
                log.debug("HydeService: AI provider unavailable for question='{}'", question);
                return HydeResult.unavailable();
            }

            JsonNode payload = objectMapper.readTree(result.payload());
            JsonNode answerNode = payload.get("hypotheticalAnswer");
            if (answerNode == null || answerNode.isNull() || answerNode.asText("").isBlank()) {
                log.debug("HydeService: missing 'hypotheticalAnswer' in response for question='{}'", question);
                return HydeResult.unavailable();
            }

            String hypotheticalAnswer = answerNode.asText();
            log.debug("HydeService: generated hypothetical ({} chars) for question='{}'",
                    hypotheticalAnswer.length(), question);
            return new HydeResult(true, hypotheticalAnswer);

        } catch (Exception e) {
            log.warn("HydeService: failed to generate hypothetical for question='{}': {}", question, e.getMessage());
            return HydeResult.unavailable();
        }
    }

    // ── Inner record ─────────────────────────────────────────────────────

    /**
     * Result of a HyDE hypothetical-document generation request.
     *
     * @param available         {@code false} if the provider was unavailable or
     *                          parsing failed
     * @param hypotheticalAnswer the generated hypothetical answer text, or
     *                          {@code null} when unavailable
     */
    public record HydeResult(boolean available, String hypotheticalAnswer) {

        /** Convenience factory for a failed/degraded result. */
        public static HydeResult unavailable() {
            return new HydeResult(false, null);
        }
    }
}

package com.weeklycommit.ai.rag;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.domain.entity.CarryForwardFact;
import com.weeklycommit.domain.entity.ComplianceFact;
import com.weeklycommit.domain.entity.TeamMembership;
import com.weeklycommit.domain.entity.TeamWeekRollup;
import com.weeklycommit.domain.entity.UserWeekFact;
import com.weeklycommit.domain.repository.CarryForwardFactRepository;
import com.weeklycommit.domain.repository.ComplianceFactRepository;
import com.weeklycommit.domain.repository.RcdoWeekRollupRepository;
import com.weeklycommit.domain.repository.TeamMembershipRepository;
import com.weeklycommit.domain.repository.TeamWeekRollupRepository;
import com.weeklycommit.domain.repository.UserWeekFactRepository;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import java.util.stream.Collectors;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

/**
 * Routes analytical and compliance questions to pre-computed read model tables
 * instead of the vector search path.
 *
 * <p>
 * This avoids costly semantic retrieval for questions that can be answered
 * directly from aggregate fact tables (e.g. team-week rollups, compliance
 * facts).
 *
 * <p>
 * The {@link #canHandle} method is a fast gate check. Callers should call it
 * first and fall back to the vector path when it returns {@code false}.
 */
@Service
public class SqlQueryRouter {

    private static final Logger log = LoggerFactory.getLogger(SqlQueryRouter.class);

    /** Aggregation keywords that indicate an analytical (non-vector) query. */
    private static final Set<String> AGGREGATION_KEYWORDS = Set.of(
            "total", "average", "most", "least", "how many", "percentage",
            "rate", "trend", "compare", "ranking", "count", "sum", "ratio",
            "highest", "lowest", "across", "breakdown");

    private final TeamMembershipRepository teamMembershipRepo;
    private final UserWeekFactRepository userWeekFactRepo;
    private final TeamWeekRollupRepository teamWeekRollupRepo;
    private final RcdoWeekRollupRepository rcdoWeekRollupRepo;
    private final CarryForwardFactRepository carryForwardFactRepo;
    private final ComplianceFactRepository complianceFactRepo;
    private final AiProviderRegistry aiProviderRegistry;
    private final ObjectMapper objectMapper;

    public SqlQueryRouter(
            TeamMembershipRepository teamMembershipRepo,
            UserWeekFactRepository userWeekFactRepo,
            TeamWeekRollupRepository teamWeekRollupRepo,
            RcdoWeekRollupRepository rcdoWeekRollupRepo,
            CarryForwardFactRepository carryForwardFactRepo,
            ComplianceFactRepository complianceFactRepo,
            AiProviderRegistry aiProviderRegistry,
            ObjectMapper objectMapper) {
        this.teamMembershipRepo = teamMembershipRepo;
        this.userWeekFactRepo = userWeekFactRepo;
        this.teamWeekRollupRepo = teamWeekRollupRepo;
        this.rcdoWeekRollupRepo = rcdoWeekRollupRepo;
        this.carryForwardFactRepo = carryForwardFactRepo;
        this.complianceFactRepo = complianceFactRepo;
        this.aiProviderRegistry = aiProviderRegistry;
        this.objectMapper = objectMapper;
    }

    // ── Public API ───────────────────────────────────────────────────────

    /**
     * Returns {@code true} when this router can handle the question without
     * vector search.
     *
     * <p>
     * Handles:
     * <ul>
     * <li>{@code "analytical"} intent — always routed here</li>
     * <li>{@code "compliance_query"} intent — always routed here</li>
     * <li>{@code "status_query"} intent with aggregation keywords</li>
     * </ul>
     *
     * @param intent   classified intent string (may be null)
     * @param keywords extracted keywords list (may be null)
     */
    public boolean canHandle(String intent, List<String> keywords) {
        if ("analytical".equals(intent) || "compliance_query".equals(intent)) {
            return true;
        }
        if ("status_query".equals(intent) && keywords != null) {
            String combined = keywords.stream().map(String::toLowerCase).collect(Collectors.joining(" "));
            for (String agg : AGGREGATION_KEYWORDS) {
                if (combined.contains(agg)) {
                    return true;
                }
            }
        }
        return false;
    }

    /**
     * Executes an analytical query against the read model tables and synthesises
     * a natural-language answer via the LLM.
     *
     * @param question      the user's natural-language question
     * @param intent        classified intent (e.g. {@code "analytical"})
     * @param keywords      extracted keywords for data-source selection
     * @param teamId        scoping team UUID (may be null for cross-team queries)
     * @param timeRangeFrom ISO date string for the range start (may be null)
     * @param timeRangeTo   ISO date string for the range end (may be null)
     * @param userId        requesting user UUID (for audit)
     * @return a {@link SqlQueryResult}, or an unavailable result on failure
     */
    public SqlQueryResult query(
            String question,
            String intent,
            List<String> keywords,
            UUID teamId,
            String timeRangeFrom,
            String timeRangeTo,
            UUID userId) {

        try {
            LocalDate from = parseDate(timeRangeFrom);
            LocalDate to = parseDate(timeRangeTo);

            // Resolve team members for per-user fact queries
            List<UUID> memberUserIds = resolveTeamMemberIds(teamId);

            // Gather relevant read model data
            Map<String, Object> readModelData = gatherReadModelData(
                    intent, keywords, teamId, memberUserIds, from, to);

            if (readModelData.isEmpty()) {
                log.debug("SqlQueryRouter: no read model data found for question='{}'", question);
                return SqlQueryResult.unavailable();
            }

            // Build AI context with read model data as additional context
            Map<String, Object> additionalContext = new LinkedHashMap<>();
            additionalContext.put("question", question);
            additionalContext.put("readModelData", readModelData);

            AiContext context = new AiContext(
                    AiContext.TYPE_SQL_SYNTHESIS,
                    userId,
                    null,
                    null,
                    Map.of(),
                    Map.of(),
                    java.util.List.of(),
                    java.util.List.of(),
                    additionalContext);

            AiSuggestionResult result = aiProviderRegistry.generateSuggestion(context);
            if (!result.available()) {
                log.debug("SqlQueryRouter: AI provider unavailable for question='{}'", question);
                return SqlQueryResult.unavailable();
            }

            return parseSqlQueryResult(result);

        } catch (Exception e) {
            log.warn("SqlQueryRouter: failed to execute query for question='{}': {}", question, e.getMessage());
            return SqlQueryResult.unavailable();
        }
    }

    // ── Private helpers ──────────────────────────────────────────────────

    private List<UUID> resolveTeamMemberIds(UUID teamId) {
        if (teamId == null) {
            return List.of();
        }
        return teamMembershipRepo.findByTeamId(teamId).stream()
                .map(TeamMembership::getUserId)
                .collect(Collectors.toList());
    }

    private Map<String, Object> gatherReadModelData(
            String intent,
            List<String> keywords,
            UUID teamId,
            List<UUID> memberUserIds,
            LocalDate from,
            LocalDate to) {

        Map<String, Object> data = new LinkedHashMap<>();

        boolean isComplianceFocused = "compliance_query".equals(intent)
                || containsKeyword(keywords, "compliance", "locked", "lock", "reconcil");
        boolean isCarryForwardFocused = containsKeyword(keywords, "carry", "forward", "streak");
        boolean isTeamRollupFocused = "analytical".equals(intent)
                || containsKeyword(keywords, "team", "total", "average", "rate", "trend", "compare");

        // Team-level rollups
        if (teamId != null && isTeamRollupFocused) {
            List<TeamWeekRollup> rollups = fetchTeamRollups(teamId, from, to);
            if (!rollups.isEmpty()) {
                data.put("teamWeekRollups", rollups.stream()
                        .map(this::rollupToMap)
                        .collect(Collectors.toList()));
            }
        }

        // Per-user week facts
        if (!memberUserIds.isEmpty() && (isTeamRollupFocused || isComplianceFocused)) {
            List<UserWeekFact> facts = fetchUserWeekFacts(memberUserIds, from, to);
            if (!facts.isEmpty()) {
                data.put("userWeekFacts", facts.stream()
                        .map(this::userWeekFactToMap)
                        .collect(Collectors.toList()));
            }
        }

        // Carry-forward facts
        if (isCarryForwardFocused) {
            List<CarryForwardFact> cfFacts = fetchCarryForwardFacts(from, to);
            if (!cfFacts.isEmpty()) {
                data.put("carryForwardFacts", cfFacts.stream()
                        .map(this::carryForwardFactToMap)
                        .collect(Collectors.toList()));
            }
        }

        // Compliance facts
        if (isComplianceFocused && !memberUserIds.isEmpty()) {
            List<ComplianceFact> compFacts = fetchComplianceFacts(memberUserIds, from, to);
            if (!compFacts.isEmpty()) {
                data.put("complianceFacts", compFacts.stream()
                        .map(this::complianceFactToMap)
                        .collect(Collectors.toList()));
            }
        }

        return data;
    }

    private boolean containsKeyword(List<String> keywords, String... targets) {
        if (keywords == null) {
            return false;
        }
        String combined = keywords.stream().map(String::toLowerCase).collect(Collectors.joining(" "));
        for (String target : targets) {
            if (combined.contains(target.toLowerCase())) {
                return true;
            }
        }
        return false;
    }

    private List<TeamWeekRollup> fetchTeamRollups(UUID teamId, LocalDate from, LocalDate to) {
        if (from != null && to != null) {
            return teamWeekRollupRepo.findByTeamIdAndWeekStartBetween(teamId, from, to);
        }
        // Fall back to last 12 weeks if no time range
        LocalDate defaultTo = LocalDate.now();
        LocalDate defaultFrom = defaultTo.minusWeeks(12);
        return teamWeekRollupRepo.findByTeamIdAndWeekStartBetween(teamId, defaultFrom, defaultTo);
    }

    private List<UserWeekFact> fetchUserWeekFacts(List<UUID> memberIds, LocalDate from, LocalDate to) {
        if (from != null && to != null) {
            return userWeekFactRepo.findByUserIdInAndWeekStartBetween(memberIds, from, to);
        }
        return userWeekFactRepo.findByUserIdIn(memberIds);
    }

    private List<CarryForwardFact> fetchCarryForwardFacts(LocalDate from, LocalDate to) {
        if (from != null && to != null) {
            return carryForwardFactRepo.findByCurrentWeekBetween(from, to);
        }
        return carryForwardFactRepo.findAll();
    }

    private List<ComplianceFact> fetchComplianceFacts(List<UUID> memberIds, LocalDate from, LocalDate to) {
        if (from != null && to != null) {
            return complianceFactRepo.findByUserIdInAndWeekStartBetween(memberIds, from, to);
        }
        // No all-members query available — return empty for safety
        return new ArrayList<>();
    }

    private LocalDate parseDate(String dateStr) {
        if (dateStr == null || dateStr.isBlank()) {
            return null;
        }
        try {
            return LocalDate.parse(dateStr);
        } catch (Exception e) {
            log.debug("SqlQueryRouter: could not parse date '{}': {}", dateStr, e.getMessage());
            return null;
        }
    }

    private SqlQueryResult parseSqlQueryResult(AiSuggestionResult result) {
        try {
            JsonNode payload = objectMapper.readTree(result.payload());
            String answer = payload.path("answer").asText("");
            String dataSource = payload.path("dataSource").asText("read models");
            double confidence = 0.8;
            JsonNode confNode = payload.get("confidence");
            if (confNode != null && confNode.isNumber()) {
                double parsed = confNode.asDouble();
                if (parsed >= 0.0 && parsed <= 1.0) {
                    confidence = parsed;
                }
            }
            if (answer.isBlank()) {
                return SqlQueryResult.unavailable();
            }
            return new SqlQueryResult(true, answer, dataSource, confidence, result.modelVersion());
        } catch (Exception e) {
            log.warn("SqlQueryRouter: failed to parse LLM result: {}", e.getMessage());
            return SqlQueryResult.unavailable();
        }
    }

    // ── Entity → map helpers ─────────────────────────────────────────────

    private Map<String, Object> rollupToMap(TeamWeekRollup r) {
        Map<String, Object> m = new LinkedHashMap<>();
        m.put("weekStart", r.getWeekStart() != null ? r.getWeekStart().toString() : null);
        m.put("memberCount", r.getMemberCount());
        m.put("lockedCount", r.getLockedCount());
        m.put("reconciledCount", r.getReconciledCount());
        m.put("totalPlannedPoints", r.getTotalPlannedPoints());
        m.put("totalAchievedPoints", r.getTotalAchievedPoints());
        m.put("avgCarryForwardRate", r.getAvgCarryForwardRate());
        m.put("exceptionCount", r.getExceptionCount());
        return m;
    }

    private Map<String, Object> userWeekFactToMap(UserWeekFact f) {
        Map<String, Object> m = new LinkedHashMap<>();
        m.put("userId", f.getUserId() != null ? f.getUserId().toString() : null);
        m.put("weekStart", f.getWeekStart() != null ? f.getWeekStart().toString() : null);
        m.put("planState", f.getPlanState());
        m.put("lockCompliance", f.isLockCompliance());
        m.put("reconcileCompliance", f.isReconcileCompliance());
        m.put("totalPlannedPoints", f.getTotalPlannedPoints());
        m.put("totalAchievedPoints", f.getTotalAchievedPoints());
        m.put("commitCount", f.getCommitCount());
        m.put("carryForwardCount", f.getCarryForwardCount());
        m.put("kingCount", f.getKingCount());
        m.put("queenCount", f.getQueenCount());
        return m;
    }

    private Map<String, Object> carryForwardFactToMap(CarryForwardFact f) {
        Map<String, Object> m = new HashMap<>();
        m.put("commitId", f.getCommitId() != null ? f.getCommitId().toString() : null);
        m.put("streakLength", f.getStreakLength());
        m.put("chessPiece", f.getChessPiece());
        m.put("sourceWeek", f.getSourceWeek() != null ? f.getSourceWeek().toString() : null);
        m.put("currentWeek", f.getCurrentWeek() != null ? f.getCurrentWeek().toString() : null);
        return m;
    }

    private Map<String, Object> complianceFactToMap(ComplianceFact f) {
        Map<String, Object> m = new LinkedHashMap<>();
        m.put("userId", f.getUserId() != null ? f.getUserId().toString() : null);
        m.put("weekStart", f.getWeekStart() != null ? f.getWeekStart().toString() : null);
        m.put("lockOnTime", f.isLockOnTime());
        m.put("lockLate", f.isLockLate());
        m.put("autoLocked", f.isAutoLocked());
        m.put("reconcileOnTime", f.isReconcileOnTime());
        m.put("reconcileLate", f.isReconcileLate());
        m.put("reconcileMissed", f.isReconcileMissed());
        return m;
    }

    // ── Inner record ─────────────────────────────────────────────────────

    /**
     * Result of an analytical SQL-routing query.
     *
     * @param available    {@code false} if the provider was unavailable or data was
     *                     insufficient
     * @param answer       synthesised natural-language answer
     * @param dataSource   name of the primary read model(s) used
     * @param confidence   LLM confidence in the answer [0.0, 1.0]
     * @param suggestionId model version identifier (for audit)
     */
    public record SqlQueryResult(
            boolean available,
            String answer,
            String dataSource,
            double confidence,
            String suggestionId) {

        /** Convenience factory for a failed/degraded result. */
        public static SqlQueryResult unavailable() {
            return new SqlQueryResult(false, null, null, 0.0, null);
        }
    }
}

package com.weeklycommit.ai.rag;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.never;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import java.util.UUID;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.ArgumentCaptor;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

/**
 * Unit tests for {@link HydeService}.
 *
 * <p>
 * Uses a mocked {@link AiProviderRegistry} so no real HTTP calls are made.
 */
@ExtendWith(MockitoExtension.class)
class HydeServiceTest {

    @Mock
    private AiProviderRegistry aiProviderRegistry;

    private final ObjectMapper objectMapper = new ObjectMapper();

    private HydeService hydeService;

    @BeforeEach
    void setUp() {
        hydeService = new HydeService(aiProviderRegistry, objectMapper);
    }

    // ── Short-circuit paths ──────────────────────────────────────────────

    @Test
    void generateHypothetical_nullQuestion_returnsUnavailable() {
        HydeService.HydeResult result = hydeService.generateHypothetical(null, UUID.randomUUID());

        assertThat(result.available()).isFalse();
        assertThat(result.hypotheticalAnswer()).isNull();
        verify(aiProviderRegistry, never()).generateSuggestion(any());
    }

    @Test
    void generateHypothetical_blankQuestion_returnsUnavailable() {
        HydeService.HydeResult result = hydeService.generateHypothetical("   ", UUID.randomUUID());

        assertThat(result.available()).isFalse();
        verify(aiProviderRegistry, never()).generateSuggestion(any());
    }

    // ── Provider unavailable ─────────────────────────────────────────────

    @Test
    void generateHypothetical_providerUnavailable_returnsUnavailable() {
        when(aiProviderRegistry.generateSuggestion(any())).thenReturn(AiSuggestionResult.unavailable());

        HydeService.HydeResult result =
                hydeService.generateHypothetical("What did the team commit to?", UUID.randomUUID());

        assertThat(result.available()).isFalse();
        assertThat(result.hypotheticalAnswer()).isNull();
    }

    // ── Happy path ───────────────────────────────────────────────────────

    @Test
    void generateHypothetical_validResponse_returnsHypotheticalAnswer() throws Exception {
        String payload =
                objectMapper.writeValueAsString(
                        java.util.Map.of(
                                "hypotheticalAnswer",
                                "The team committed to 10 work items with 2 KING priorities and 24 total points."));
        when(aiProviderRegistry.generateSuggestion(any()))
                .thenReturn(new AiSuggestionResult(true, payload, "rationale", 0.85, "model-v1"));

        HydeService.HydeResult result =
                hydeService.generateHypothetical("What did the team commit to last week?", UUID.randomUUID());

        assertThat(result.available()).isTrue();
        assertThat(result.hypotheticalAnswer()).contains("10 work items").contains("KING");
    }

    @Test
    void generateHypothetical_usesTypeHydeContext() {
        when(aiProviderRegistry.generateSuggestion(any())).thenReturn(AiSuggestionResult.unavailable());
        ArgumentCaptor<AiContext> captor = ArgumentCaptor.forClass(AiContext.class);

        hydeService.generateHypothetical("some question", UUID.randomUUID());

        verify(aiProviderRegistry).generateSuggestion(captor.capture());
        assertThat(captor.getValue().suggestionType()).isEqualTo(AiContext.TYPE_HYDE);
    }

    @Test
    void generateHypothetical_passesQuestionInAdditionalContext() {
        when(aiProviderRegistry.generateSuggestion(any())).thenReturn(AiSuggestionResult.unavailable());
        ArgumentCaptor<AiContext> captor = ArgumentCaptor.forClass(AiContext.class);
        String question = "What is the carry-forward rate?";

        hydeService.generateHypothetical(question, UUID.randomUUID());

        verify(aiProviderRegistry).generateSuggestion(captor.capture());
        assertThat(captor.getValue().additionalContext()).containsEntry("question", question);
    }

    @Test
    void generateHypothetical_nullUserId_doesNotThrow() throws Exception {
        String payload =
                objectMapper.writeValueAsString(
                        java.util.Map.of("hypotheticalAnswer", "A plausible answer."));
        when(aiProviderRegistry.generateSuggestion(any()))
                .thenReturn(new AiSuggestionResult(true, payload, "rationale", 0.8, "model-v1"));

        HydeService.HydeResult result = hydeService.generateHypothetical("some question", null);

        assertThat(result.available()).isTrue();
    }

    // ── Malformed responses ──────────────────────────────────────────────

    @Test
    void generateHypothetical_missingHypotheticalAnswerField_returnsUnavailable() throws Exception {
        String payload = objectMapper.writeValueAsString(java.util.Map.of("other", "value"));
        when(aiProviderRegistry.generateSuggestion(any()))
                .thenReturn(new AiSuggestionResult(true, payload, "rationale", 0.8, "model-v1"));

        HydeService.HydeResult result =
                hydeService.generateHypothetical("some question", UUID.randomUUID());

        assertThat(result.available()).isFalse();
    }

    @Test
    void generateHypothetical_malformedJson_returnsUnavailable() {
        when(aiProviderRegistry.generateSuggestion(any()))
                .thenReturn(new AiSuggestionResult(true, "not-json", "rationale", 0.8, "model-v1"));

        HydeService.HydeResult result =
                hydeService.generateHypothetical("some question", UUID.randomUUID());

        assertThat(result.available()).isFalse();
